Here are the public test cases for feature2_automatic_time_claims:
{
  "description": "Encode tokens using automatic time-claim behavior and render whether issue-time and expiration claims are present after decoding.",
  "cases": [
    {
      "input": {
        "action": "encode_then_decode",
        "encode_args": [
          "encode",
          "--exp",
          "-S",
          "1234567890"
        ],
        "decode_args": [
          "decode",
          "-S",
          "1234567890"
        ],
        "report": [
          "status",
          "claim.iat.presence",
          "claim.exp.presence"
        ]
      },
      "expected_output": "status=valid\nclaim.iat=present\nclaim.exp=present\n"
    },
    {
      "input": {
        "action": "encode_then_decode",
        "encode_args": [
          "encode",
          "--no-iat",
          "--exp",
          "-S",
          "1234567890"
        ],
        "decode_args": [
          "decode",
          "-S",
          "1234567890"
        ],
        "report": [
          "status",
          "claim.iat.presence",
          "claim.exp.presence"
        ]
      },
      "expected_output": "status=valid\nclaim.iat=absent\nclaim.exp=present\n"
    }
  ]
}

Here are the public test cases for feature3_relative_time_expressions:
{
  "description": "Encode tokens with relative duration expressions for time-based claims and render the decoded second offsets from the generated issue time.",
  "cases": [
    {
      "input": {
        "action": "encode_then_decode",
        "encode_args": [
          "encode",
          "-S",
          "1234567890",
          "-e",
          "+10 min -30 sec"
        ],
        "decode_args": [
          "decode",
          "-S",
          "1234567890"
        ],
        "report": [
          "status",
          "claim.exp_minus_iat"
        ]
      },
      "expected_output": "status=valid\nclaim.exp_minus_iat=570\n"
    },
    {
      "input": {
        "action": "encode_then_decode",
        "encode_args": [
          "encode",
          "-S",
          "1234567890",
          "--exp",
          "-n",
          "+5 min"
        ],
        "decode_args": [
          "decode",
          "-S",
          "1234567890"
        ],
        "report": [
          "status",
          "claim.nbf_minus_iat"
        ]
      },
      "expected_output": "status=valid\nclaim.nbf_minus_iat=300\n"
    }
  ]
}

Here are the public test cases for feature4_decode_existing_tokens:
{
  "description": "Decode existing token strings under verified, unverified, whitespace-trimmed, and invalid-signature conditions and render observable status plus selected fields.",
  "cases": [
    {
      "input": {
        "action": "decode",
        "args": [
          "decode",
          "eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9.eyJleHAiOjE4OTM0NTYwMDAsImlhdCI6MTU0MjQ5MjMxMywidGhpcyI6InRoYXQifQ.YTWit46_AEMMVv0P48NeJJIqXmMHarGjfRxtR7jLlxE",
          "-S",
          "1234567890",
          "-A",
          "HS256"
        ],
        "report": [
          "status",
          "header.alg",
          "header.typ",
          "claim.exp",
          "claim.iat",
          "claim.this"
        ]
      },
      "expected_output": "status=valid\nheader.alg=HS256\nheader.typ=JWT\nclaim.exp=1893456000\nclaim.iat=1542492313\nclaim.this=that\n"
    },
    {
      "input": {
        "action": "decode",
        "args": [
          "decode",
          "eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9.eyJ0aGlzIjoidGhhdCJ9.AdAECLE_4iRa0uomMEdsMV2hDXv1vhLpym567-AzhrM",
          "-S",
          "yolo",
          "-A",
          "HS256"
        ],
        "report": [
          "status",
          "error",
          "header.alg",
          "claim.this"
        ]
      },
      "expected_output": "status=invalid\nerror=invalid_signature\nheader.alg=HS256\nclaim.this=that\n"
    }
  ]
}

Here are the public test cases for feature5_key_files:
{
  "description": "Encode tokens using key material loaded from files and verify the produced tokens with the matching file-backed verification input.",
  "cases": [
    {
      "input": {
        "action": "encode_then_decode",
        "encode_args": [
          "encode",
          "-A",
          "RS256",
          "--exp",
          "-S",
          "@./tests/private_rsa_key.der",
          "{\"field\":\"value\"}"
        ],
        "decode_args": [
          "decode",
          "-S",
          "@./tests/public_rsa_key.der",
          "-A",
          "RS256"
        ],
        "report": [
          "status",
          "header.alg",
          "claim.field"
        ]
      },
      "expected_output": "status=valid\nheader.alg=RS256\nclaim.field=value\n"
    }
  ]
}

